// Solution
function queryProjection(doc, query) {
  let result = {};
  for (let key in doc) {
    if (query[key] !== undefined) {
      result[key] = query[key] === '$name' ? doc[key] : { [key.split('.')[0]]: { [key.split('.')[1]]: doc[key] } };
    }
  }
  return result;
}

