class Solution:
  def queryProjection(self, doc, query):
    result = {}
    for key in doc:
      if key in query:
        if query[key] == "$name":
          result['name'] = doc[key]
        elif key.split('.')[1] == 'city':
          result['address'] = { 'city': doc[key] }
    return result
